import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/network/chapter-6.md","filePath":"szu/network/chapter-6.md"}'),o={name:"szu/network/chapter-6.md"};function r(u,l,n,h,s,c){return a(),e("div",null,[...l[0]||(l[0]=[t('<h2 id="一-、数据通信基础" tabindex="-1">(一)、数据通信基础 <a class="header-anchor" href="#一-、数据通信基础" aria-label="Permalink to &quot;(一)、数据通信基础&quot;">​</a></h2><ol><li>数据通信基本概念 <ul><li>1.消息与信息 <ul><li>声音、文字、图像、气味等称为消息。</li><li>信息是一个抽象的概念，可以理解为消息中所包含有意义的内容，而消息是信息的载体。</li></ul></li><li>2.通信 <ul><li>通信的本质就是在一点精确或近似地再生另一点的信息。</li></ul></li><li>3.信号</li><li>4.数据</li><li>5.信道</li></ul></li><li>数据通信系统模型 <ul><li>数据通信系统的构成 <ul><li>信息源、发送设备、信道（可能存在噪声源）、接收设备、信宿</li></ul></li><li>模拟通信和数字通信</li><li>数据通信方式 <ul><li>单向通信、双向交替通信和双向同时通信</li><li>并行通信和串行通信</li><li>异步通信和同步通信</li></ul></li><li>数据通信系统的功能</li></ul></li></ol><h2 id="二-、物理介质" tabindex="-1">(二)、物理介质 <a class="header-anchor" href="#二-、物理介质" aria-label="Permalink to &quot;(二)、物理介质&quot;">​</a></h2><ol><li><p>导引型传输介质</p><ul><li>架空明线</li><li>双绞线</li><li>同轴电缆</li><li>光纤</li></ul></li><li><p>非导引型传输介质</p><ul><li>地波传播</li><li>天波传播</li><li>视线传播</li></ul></li></ol><h2 id="三-、信道与信道容量" tabindex="-1">(三)、信道与信道容量 <a class="header-anchor" href="#三-、信道与信道容量" aria-label="Permalink to &quot;(三)、信道与信道容量&quot;">​</a></h2><ol><li>信道分类与模型 <ul><li>调制信道</li><li>编码信道</li></ul></li><li>信道传输特性 <ul><li>恒参信道传输特性</li><li>随参信道传输特性</li></ul></li><li>信道容量 <ul><li>连续信道容量</li><li>离散信道容量</li></ul></li></ol><h2 id="四-、基带传输" tabindex="-1">(四)、基带传输 <a class="header-anchor" href="#四-、基带传输" aria-label="Permalink to &quot;(四)、基带传输&quot;">​</a></h2><ol><li>基带传输基本概念</li><li>数字基带传输编码 <ul><li>单极不归零码（NRZ）</li><li>双极不归零码</li><li>单极归零码（RZ）</li><li>双极归零码</li><li>差分码 <ul><li>AMI 码</li><li>双相码</li><li>米勒码</li><li>CMI 码</li><li>nBmB 码</li><li>nBmT 码</li></ul></li></ul></li></ol><h2 id="五-、频带传输" tabindex="-1">(五)、频带传输 <a class="header-anchor" href="#五-、频带传输" aria-label="Permalink to &quot;(五)、频带传输&quot;">​</a></h2><ol><li>频带传输基本概念 <ul><li>通常将实现调制、传输与调解的传输系统称为数字频带传输系统。频带传输也称为通带传输或载波传输。</li></ul></li><li>频带传输的三种调制方式 <ul><li>1.二进制数字调制 <ul><li>包括：二进制福移键控、二进制频移键控、二进制相移键控</li><li>二进制差分相移键控</li><li>二进制数字调制性能</li></ul></li><li>2.多进制数字调制</li><li>3.正交幅值调控 QAM</li></ul></li></ol><h2 id="六-、物理层接口规程" tabindex="-1">(六)、物理层接口规程 <a class="header-anchor" href="#六-、物理层接口规程" aria-label="Permalink to &quot;(六)、物理层接口规程&quot;">​</a></h2><ol><li><p>物理层接口概述</p><ul><li>四大特性：机械特性、电气特性、功能特性、规程特性</li></ul></li><li><p>物理层接口特性</p><ul><li>1.机械特性</li><li>2.电气特性</li><li>3.功能特性</li><li>4.规程特性</li></ul></li></ol>',12)])])}const _=i(o,[["render",r]]);export{p as __pageData,_ as default};
